export type ErrorFormat = 'pretty' | 'colorless' | 'minimal'
export type PrismaClientOptions = ({
  /**
   * Instance of a Driver Adapter, e.g., like one provided by `@prisma/adapter-pg`.
   */
  adapter: runtime.SqlDriverAdapterFactory
  accelerateUrl?: never
} | {
  /**
   * Prisma Accelerate URL allowing the client to connect through Accelerate instead of a direct database.
   */
  accelerateUrl: string
  adapter?: never
}) & {
  /**
   * @default "colorless"
   */
  errorFormat?: ErrorFormat
  /**
   * @example
   * ```
   * // Shorthand for `emit: 'stdout'`
   * log: ['query', 'info', 'warn', 'error']
   * 
   * // Emit as events only
   * log: [
   *   { emit: 'event', level: 'query' },
   *   { emit: 'event', level: 'info' },
   *   { emit: 'event', level: 'warn' }
   *   { emit: 'event', level: 'error' }
   * ]
   * 
   * / Emit as events and log to stdout
   * og: [
   *  { emit: 'stdout', level: 'query' },
   *  { emit: 'stdout', level: 'info' },
   *  { emit: 'stdout', level: 'warn' }
   *  { emit: 'stdout', level: 'error' }
   * 
   * ```
   * Read more in our [docs](https://pris.ly/d/logging).
   */
  log?: (LogLevel | LogDefinition)[]
  /**
   * The default values for transactionOptions
   * maxWait ?= 2000
   * timeout ?= 5000
   */
  transactionOptions?: {
    maxWait?: number
    timeout?: number
    isolationLevel?: TransactionIsolationLevel
  }
  /**
   * Global configuration for omitting model fields by default.
   * 
   * @example
   * ```
   * const prisma = new PrismaClient({
   *   omit: {
   *     user: {
   *       password: true
   *     }
   *   }
   * })
   * ```
   */
  omit?: GlobalOmitConfig
  /**
   * SQL commenter plugins that add metadata to SQL queries as comments.
   * Comments follow the sqlcommenter format: https://google.github.io/sqlcommenter/
   * 
   * @example
   * ```
   * const prisma = new PrismaClient({
   *   adapter,
   *   comments: [
   *     traceContext(),
   *     queryInsights(),
   *   ],
   * })
   * ```
   */
  comments?: runtime.SqlCommenterPlugin[]
  /**
   * Optional maximum size for the query plan cache. If not provided, a default size will be used.
   * A value of `0` can be used to disable the cache entirely. A higher cache size can improve
   * performance for applications that execute a large number of unique queries, while a smaller
   * cache size can reduce memory usage.
   * 
   * @example
   * ```
   * const prisma = new PrismaClient({
   *   adapter,
   *   queryPlanCacheMaxSize: 100,
   * })
   * ```
   */
  queryPlanCacheMaxSize?: number
}
export type GlobalOmitConfig = {
  asset_categories?: Prisma.asset_categoriesOmit
  asset_status_history?: Prisma.asset_status_historyOmit
  assets?: Prisma.assetsOmit
  audit_logs?: Prisma.audit_logsOmit
  branches?: Prisma.branchesOmit
  electrical_maintenance_details?: Prisma.electrical_maintenance_detailsOmit
  escalation_rules?: Prisma.escalation_rulesOmit
  generator_maintenance_details?: Prisma.generator_maintenance_detailsOmit
  hardware_maintenance_details?: Prisma.hardware_maintenance_detailsOmit
  maintenance_requests?: Prisma.maintenance_requestsOmit
  notification_types?: Prisma.notification_typesOmit
  notifications?: Prisma.notificationsOmit
  on_hold_reasons?: Prisma.on_hold_reasonsOmit
  preventive_maintenance_logs?: Prisma.preventive_maintenance_logsOmit
  preventive_maintenance_schedules?: Prisma.preventive_maintenance_schedulesOmit
  priority_levels?: Prisma.priority_levelsOmit
  request_disposal_details?: Prisma.request_disposal_detailsOmit
  request_escalations?: Prisma.request_escalationsOmit
  request_on_hold_details?: Prisma.request_on_hold_detailsOmit
  request_resolution_details?: Prisma.request_resolution_detailsOmit
  request_sla_tracking?: Prisma.request_sla_trackingOmit
  request_spare_parts_used?: Prisma.request_spare_parts_usedOmit
  request_statuses?: Prisma.request_statusesOmit
  responsible_party_types?: Prisma.responsible_party_typesOmit
  roles?: Prisma.rolesOmit
  spare_parts?: Prisma.spare_partsOmit
  users?: Prisma.usersOmit
  vendor_contracts?: Prisma.vendor_contractsOmit
  vendor_request_assignments?: Prisma.vendor_request_assignmentsOmit
  vendors?: Prisma.vendorsOmit
}

/* Types for Logging */
export type LogLevel = 'info' | 'query' | 'warn' | 'error'
export type LogDefinition = {
  level: LogLevel
  emit: 'stdout' | 'event'
}

export type CheckIsLogLevel<T> = T extends LogLevel ? T : never;

export type GetLogType<T> = CheckIsLogLevel<
  T extends LogDefinition ? T['level'] : T
>;

export type GetEvents<T extends any[]> = T extends Array<LogLevel | LogDefinition>
  ? GetLogType<T[number]>
  : never;

export type QueryEvent = {
  timestamp: Date
  query: string
  params: string
  duration: number
  target: string
}

export type LogEvent = {
  timestamp: Date
  message: string
  target: string
}
/* End Types for Logging */


export type PrismaAction =
  | 'findUnique'
  | 'findUniqueOrThrow'
  | 'findMany'
  | 'findFirst'
  | 'findFirstOrThrow'
  | 'create'
  | 'createMany'
  | 'createManyAndReturn'
  | 'update'
  | 'updateMany'
  | 'updateManyAndReturn'
  | 'upsert'
  | 'delete'
  | 'deleteMany'
  | 'executeRaw'
  | 'queryRaw'
  | 'aggregate'
  | 'count'
  | 'runCommandRaw'
  | 'findRaw'
  | 'groupBy'

/**
 * `PrismaClient` proxy available in interactive transactions.
 */
export type TransactionClient = Omit<DefaultPrismaClient, runtime.ITXClientDenyList>

